UPDATE skin_float_range SET image_url = CASE skin_id
WHEN #{row.skinId} THEN #{row.image}
END WHERE skin_id IN
#{row.skinId}
AND (image_url IS NULL OR image_url = '')

mapper.select:
SELECT 
FROM skin_float_range
WHERE base_name_en = #{key}
   OR base_name_zh = #{key}
LIMIT 1

SELECT FROM skin_float_range WHERE 1 = 1
AND (collection_zh LIKE CONCAT('%', #{collection}, '%') OR collection_en LIKE CONCAT('%', #{collection}, '%'))
AND (name_zh LIKE CONCAT('%', #{name}, '%') OR name_en LIKE CONCAT('%', #{name}, '%'))
AND rarity = #{rarity}
ORDER BY name_en ASC LIMIT #{limit}

SELECT DISTINCT name_zh
FROM skin_float_range
WHERE collection_zh = #{collectionZh}
  AND rarity = #{rarity}
  AND name_zh IS NOT NULL
  AND name_zh <> ''
